module RefModule(
	input clk,
	input reset,
	input up,
	input down,
	output reg [3:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
	begin
		if (reset)
			q <= 4'b0000;
		else if (up)
			q <= q + 1;
		else if (down)
			q <= q - 1;
	end
endmodule
